return $input.all().map(({ json: u }) => ({ json: {
  user_id: u.user_id,
  system: 'You are a builder\'s companion. ONE warm, specific sentence (max two) about their recent shipping. Reference a real event. Never generic, never naggy, no emojis spam.',
  user: `Builder: ${u.display_name}. Streak: ${u.streak_current} days. Recent ships: ${JSON.stringify(u.recent ?? [])}. Write today's single nudge.`
}}));
